/* Example for a main heading */
h1 {
    font-size: clamp(2rem, 5vw + 1rem, 4rem);
    /* Minimum: 2rem */
    /* Fluid: scales with 5% of viewport width + 1rem */
    /* Maximum: 4rem */
    line-height: 1.2; /* Complementary for good readability */
}

/* Example for body text */
p {
    font-size: clamp(1rem, 2vw + 0.5rem, 1.25rem);
    line-height: 1.6;
}

/* Remember to define your web fonts for superior UI */
body {
    font-family: 'Inter', sans-serif;
    text-rendering: optimizeLegibility;
}

body {
  -webkit-hyphens: auto; /* For older WebKit browsers */
  -ms-hyphens: auto;    /* For Internet Explorer */
  hyphens: auto;        /* Standard property */
  word-break: break-word; /* Ensure long words don't overflow */
}

/* For best results, ensure the lang attribute is set on the HTML or relevant element, e.g., <html lang="en"> */
.article-content {
  hyphens: auto;
  text-align: justify; /* Often used effectively with hyphens */
  -webkit-hyphens: auto;
  -ms-hyphens: auto;
}

@font-face {
  font-family: 'Inter';
  src: url('/fonts/Inter-Regular.woff2') format('woff2');
  font-weight: 400;
  font-display: swap; /* Ensures immediate text visibility */
}

@font-face {
  font-family: 'IconFont';
  src: url('/fonts/Icons.woff2') format('woff2');
  font-weight: normal;
  font-display: optional; /* Less critical, optional load */
}

body {
  font-family: 'Inter', sans-serif;
}

/* Example for establishing hierarchy */
h1 {
  font-size: 2.5rem;
  font-weight: 700;
  text-transform: uppercase;
  margin-bottom: 0.75em;
  color: #2c3e50;
}

h2 {
  font-size: 1.8rem;
  font-weight: 600;
  margin-bottom: 0.6em;
  color: #34495e;
}

p {
  font-size: 1rem;
  line-height: 1.6;
  margin-bottom: 1em;
  color: #555;
}

strong {
  font-weight: 700;
  color: #333;
}

::selection {
  background-color: #A0C4FF; /* Your brand's accent color */
  color: #000000;          /* Text color when selected */
}

/* For older WebKit browsers (optional) */
::-webkit-selection {
  background-color: #A0C4FF;
  color: #000000;
}

/* For Firefox */
::-moz-selection {
  background-color: #A0C4FF;
  color: #000000;
}

body {
  font-family: "Inter", "Helvetica Neue", "Arial", sans-serif;
  /* These properties enhance text rendering for better UI readability */
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

/* Ensure the variable font is declared with a wide range for its axes */
@font-face {
  font-family: 'Inter Variable';
  src: url('Inter-VariableFont.woff2') format('woff2');
  font-weight: 100 900; /* Define the weight axis range */
  font-display: swap;
}

body {
  font-family: 'Inter Variable', sans-serif;
  font-weight: 400; /* Default weight */
}

h1 {
  /* Using font-variation-settings for explicit control of axes */
  font-variation-settings: 'wght' 700, 'slnt' -10; /* Weight 700, Slant -10 */
}

.dynamic-text {
  transition: font-variation-settings 0.3s ease;
}

.dynamic-text:hover {
  font-variation-settings: 'wght' 900, 'wdth' 120; /* Example: bolder and wider on hover */
}

:root {
  --font-primary: 'Inter', sans-serif;
  --font-secondary: 'Merriweather', serif;

  --text-base-size: 1rem;
  --text-lg-size: 1.25rem;
  --text-xl-size: 1.5rem;

  --font-weight-regular: 400;
  --font-weight-bold: 700;

  --line-height-body: 1.6;
  --line-height-heading: 1.2;
}

body {
  font-family: var(--font-primary);
  font-size: var(--text-base-size);
  line-height: var(--line-height-body);
}

h1 {
  font-family: var(--font-secondary);
  font-size: var(--text-xl-size);
  font-weight: var(--font-weight-bold);
  line-height: var(--line-height-heading);
}

@font-face {
  font-family: 'AppBrandFont';
  src: url('/fonts/AppBrandFont-Regular.woff2') format('woff2') tech('woff2'),
       url('/fonts/AppBrandFont-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* 'swap' for quick fallback, 'optional' for less intrusive loading */
}

@font-face {
  font-family: 'AppBrandFont';
  src: url('/fonts/AppBrandFont-Bold.woff2') format('woff2') tech('woff2'),
       url('/fonts/AppBrandFont-Bold.woff') format('woff');
  font-weight: 700;
  font-style: normal;
  font-display: swap;
}

body {
  font-family: 'AppBrandFont', 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Body text for readability */
body {
  font-family: 'Inter', sans-serif;
  font-size: 18px; /* Base font size */
  line-height: 1.5; /* Optimal for readability: 18px * 1.5 = 27px line height */
  letter-spacing: -0.01em; /* Subtle negative spacing for better visual flow */
  color: #333;
}

/* Headings for visual impact */
h1 {
  font-family: 'DM Serif Display', serif;
  font-size: 48px;
  line-height: 1.1; /* Tighter for large headings */
  letter-spacing: -0.02em; /* More aggressive negative spacing for display fonts */
  color: #1a1a1a;
}

/* All-caps text (e.g., buttons, tags) */
.uppercase-label {
  text-transform: uppercase;
  font-size: 14px;
  letter-spacing: 0.08em; /* Positive spacing enhances readability for all-caps */
  line-height: 1.2;
}

:root {
  --min-font-size: 1rem;
  --max-font-size: 1.25rem;
  --min-vw: 20rem; /* 320px */
  --max-vw: 80rem; /* 1280px */
  --fluid-ratio: calc((var(--max-font-size) - var(--min-font-size)) / (var(--max-vw) - var(--min-vw)));
}

body {
  font-family: 'Inter', sans-serif;
  font-size: clamp(var(--min-font-size), calc(var(--min-font-size) + (var(--fluid-ratio) * (100vw - var(--min-vw)))), var(--max-font-size));
  line-height: clamp(1.4, calc(1.4 + (var(--fluid-ratio) * (100vw - var(--min-vw)) * 0.5)), 1.6); /* Adjust line-height proportionally */
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

h1 {
  /* Example for heading, scales larger */
  --min-h1-size: 2rem;
  --max-h1-size: 4rem;
  font-size: clamp(var(--min-h1-size), calc(var(--min-h1-size) + ((var(--max-h1-size) - var(--min-h1-size)) / (var(--max-vw) - var(--min-vw))) * (100vw - var(--min-vw))), var(--max-h1-size));
  line-height: 1.1;
}
